import { FormattedMessage } from 'react-intl';

import Colors from '@dynatrace/strato-design-tokens/colors';
import Typography from '@dynatrace/strato-design-tokens/typography';

import type { FilterFieldProps } from '../../FilterField.types.js';
import { filterFieldMessages } from '../../messages.js';
import type { FilterFieldSuggestion } from '../../suggestions/Suggestion.types.js';
import type { InternalValidatorMap } from '../validation-utils/normalize-validator-map.js';
import { getValidOperatorsShort } from '../validation-utils/validation-helper-functions.js';

/** @internal */
export function getComparisonOperatorSuggestions(
  key: string | undefined,
  internalValidatorMap: InternalValidatorMap | undefined,
  parserConfig: FilterFieldProps['parserConfig'],
): FilterFieldSuggestion[] {
  const operators = getValidOperatorsShort(
    key,
    internalValidatorMap,
    parserConfig,
  );

  // check for explicitly defined suggestions or fallback to simple suggestion
  return operators.map((operator) => {
    const operatorWithDetails = operatorSuggestionsWithDetails[operator];
    const baseProps = {
      suggestionType: 'validatorMap',
    } as const;

    return operatorWithDetails
      ? { ...operatorWithDetails, ...baseProps }
      : { value: operator, ...baseProps };
  });
}

/** @internal */
export const defaultLogicalOperatorSuggestions: FilterFieldSuggestion[] = [
  { value: 'OR' },
];

/** @internal */
export const ValuePlaceholder = () => {
  return (
    <span
      style={{
        color: Colors.Text.Neutral.Subdued,
        fontWeight: Typography.Text.Base.Default.Weight,
      }}
    >
      value
    </span>
  );
};

